"use client";

import { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { X, FileText, ChevronRight, ChevronLeft } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Appointment } from '@/types';
import DocumentComposer from '@/components/doctor/DocumentComposer';

interface VideoConsultModalProps {
  open: boolean;
  appointment: Appointment | null;
  onClose: () => void;
  onEnd: (notes?: string) => void;
  onSendPrescription?: (payload: { diagnosis: string; medications: string; instructions: string }) => void;
  onSendLab?: (payload: { testName: string; notes: string }) => void;
  onSendCertificate?: (payload: { purpose: string; diagnosis: string; restDays: number }) => void;
  videoRoomUrl?: string;
}

export default function VideoConsultModal({
  open,
  appointment,
  onClose,
  onEnd,
  onSendPrescription,
  onSendLab,
  onSendCertificate,
  videoRoomUrl,
}: VideoConsultModalProps) {
  const jitsiUrl = videoRoomUrl ?? appointment?.videoRoomUrl;
  const [note, setNote] = useState('');
  const [panelOpen, setPanelOpen] = useState(false);
  const [showEndConfirm, setShowEndConfirm] = useState(false);

  useEffect(() => {
    if (!open) {
      setNote('');
      setPanelOpen(false);
      setShowEndConfirm(false);
    }
  }, [open]);

  if (!open) return null;

  return createPortal(
    <div className="fixed inset-0 z-[100] flex bg-gray-950">
      {/* Jitsi iframe — takes all remaining space */}
      <div className="relative flex-1 h-full">
        {jitsiUrl ? (
          <iframe
            src={jitsiUrl}
            allow="camera; microphone; fullscreen; display-capture; autoplay; clipboard-write"
            allowFullScreen
            className="absolute inset-0 w-full h-full border-0"
            title="Video Consultation"
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center text-white/50 text-sm">
            Waiting for video room…
          </div>
        )}

        {/* Top-right controls */}
        <div className="absolute top-3 right-3 flex items-center gap-2 z-10">
          <Button
            size="sm"
            variant="secondary"
            className="gap-1.5 bg-black/60 hover:bg-black/80 text-white border-0"
            onClick={() => setPanelOpen((v) => !v)}
          >
            <FileText className="h-4 w-4" />
            {panelOpen ? 'Hide Panel' : 'Documents & Notes'}
            {panelOpen ? <ChevronRight className="h-3 w-3" /> : <ChevronLeft className="h-3 w-3" />}
          </Button>
          <Button
            size="sm"
            variant="destructive"
            className="gap-1.5"
            onClick={() => setShowEndConfirm(true)}
          >
            <X className="h-4 w-4" />
            End Consult
          </Button>
        </div>
      </div>

      {/* Side panel — notes + document composer */}
      {panelOpen && (
        <div className="w-80 bg-background border-l border-border flex flex-col overflow-y-auto">
          <div className="p-4 border-b flex items-center justify-between">
            <p className="font-semibold text-sm">
              {appointment?.patient?.name ?? 'Patient'}
            </p>
            <Button variant="ghost" size="icon" onClick={() => setPanelOpen(false)}>
              <X className="h-4 w-4" />
            </Button>
          </div>

          <div className="p-4 space-y-4 flex-1">
            <div className="space-y-1.5">
              <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                Consultation Notes
              </p>
              <Input
                value={note}
                onChange={(e) => setNote(e.target.value)}
                placeholder="Quick notes…"
              />
            </div>

            <div className="space-y-1.5">
              <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                Send Document
              </p>
              <DocumentComposer
                onSendPrescription={(payload) => {
                  onSendPrescription?.(payload);
                }}
                onSendLab={(payload) => {
                  onSendLab?.(payload);
                }}
                onSendCertificate={(payload) => {
                  onSendCertificate?.(payload);
                }}
              />
            </div>
          </div>

          <div className="p-4 border-t">
            <Button
              variant="destructive"
              className="w-full"
              onClick={() => setShowEndConfirm(true)}
            >
              End Consultation
            </Button>
          </div>
        </div>
      )}

      {/* End confirmation overlay */}
      {showEndConfirm && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/60">
          <div className="bg-background rounded-xl p-6 w-80 space-y-4 shadow-xl">
            <p className="font-semibold text-base">End Consultation?</p>
            <p className="text-sm text-muted-foreground">
              Make sure you've sent any prescriptions or documents before ending.
            </p>
            <div className="flex gap-2">
              <Button variant="outline" className="flex-1" onClick={() => setShowEndConfirm(false)}>
                Back to Call
              </Button>
              <Button
                variant="destructive"
                className="flex-1"
                onClick={() => {
                  setShowEndConfirm(false);
                  onEnd(note);
                }}
              >
                End Call
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>,
    document.body
  );
}
